INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'los-angeles'), 'R1', 'r1', 'One-Family Residential', 'This zone is primarily for single-family dwellings, along with parks, playgrounds, and community centers.', 45, NULL, 5000, NULL, 25, 15, 5, '2 covered spaces per dwelling unit') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'los-angeles') AND pu.name IN ('One-Family Dwellings', 'Parks', 'Playgrounds', 'Community Centers', 'Home Occupations') ON CONFLICT DO NOTHING;
